// mask out thread that was just executed
// s_andn2_b64    s4, s4, exec
// s_mov_b64      exec, s4
s_andn2_wrexec_b64 s4, s4        // replaces above 2 ops
// repeat until EXEC==0
s_cbranch_scc1    loop
s_mov_b64      exec, s2

