v_cubetc_f32.operation:
// D0.f = cubemap T coordinate.
// XYZ coordinate is given in (S0.f, S1.f, S2.f).
// S0.f = x
// S1.f = y
// S2.f = z
if ((abs(S2.f) >= abs(S0.f)) && (abs(S2.f) >= abs(S1.f))) then
D0.f = -S1.f
elsif abs(S1.f) >= abs(S0.f) then
if S1.f < 0.0F then
D0.f = -S2.f
else
D0.f = S2.f
endif
else
D0.f = -S1.f
endif

v_cubema_f32.operation:
// D0.f = 2.0 * cubemap major axis.
// XYZ coordinate is given in (S0.f, S1.f, S2.f).
// S0.f = x
// S1.f = y
// S2.f = z
if ((abs(S2.f) >= abs(S0.f)) && (abs(S2.f) >= abs(S1.f))) then
D0.f = S2.f * 2.0F
elsif abs(S1.f) >= abs(S0.f) then
D0.f = S1.f * 2.0F
else
D0.f = S0.f * 2.0F
endif

v_sad_u8.operation:
ABSDIFF = lambda(x, y) (
x > y ? x - y : y - x);
